    if (i < Nparticles) {
        int index = -1;
        int x;
        for (x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }

        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

__kernel void normalize_weights_kernel(double * weights, int Nparticles, double* partial_sums, double * CDF, double * u, int * seed) {
    int i = threadIdx.x + blockIdx.x * blockDim.x;

    double u1, sumWeights;

    if(0 == threadIdx.x)
        sumWeights = partial_sums[0];

    if (i < Nparticles) {
        weights[i] = weights[i] / sumWeights;
    }

    if (i == 0) {
        cdfCalc(CDF, weights, Nparticles);
        u[0] = (1.0 / ((double)(Nparticles))) * d_randu(seed, i); 
    }

    if(0 == threadIdx.x) 
        u1 = u[0];

    if (i < Nparticles) {
        u[i] = u1 + i / ((double)(Nparticles));
    }
